// @ts-nocheck
// --- TYPES --------------------------------------------------------------------

export type Category = "scholarship" | "grant" | "trade" | "other" | "local"

export interface Scholarship {
  id: number
  name: string
  slug: string
  category: Category
  amount: string
  deadline: string
  gpa: string
  renewable: boolean
  url: string
  tags: string[]
  eligibility: string
  application_open?: string   // "Aug 1" — when cycle opens
  verified_by_foundation?: boolean
}

export interface LocalScholarship {
  id: string
  slug: string
  name: string
  state: string
  county: string
  city: string
  amount: string
  deadline: string
  eligibility: string
  url: string
  propublica_url: string | null
  tags: string[]
  category: "local"
  gpa: string
  renewable: boolean
  // Verified foundation fields
  verified_by_foundation?: boolean
  verified_date?: string        // "2026-03-27"
  verified_by?: string          // "Foundation contact name/title"
  application_open?: string     // "Dec 15"
  application_close?: string    // "Mar 15"
  scholarships_count?: number   // 82
  annual_awards?: string        // "~$1M"
  awards_announced?: string   // "May"
  notes?: string
  coverage?: string            // "Statewide — All of Delaware"
  contact_email?: string
  tips?: Array<{
    question: string
    answer: string
    source: string
  }>
}

// --- HELPERS ------------------------------------------------------------------

export const slugify = (s: string) =>
  s.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "")

export const CAT_META: Record<string, { label: string; icon: string; color: string }> = {
  scholarship: { label: "Scholarship",             icon: "", color: "#1a3a6b" },
  grant:       { label: "Grant",                   icon: "", color: "#0f6eb4" },
  trade:       { label: "Trades & Apprenticeships",icon: "", color: "#e85d26" },
  other:       { label: "Contests & Easy Apply",   icon: "", color: "#6b3fa0" },
  local:       { label: "Local Foundation",        icon: "", color: "#1a7a4a" },
}

